#!/usr/bin/env bash
# bin/coding-rules-check.sh — enforces WB Gamification-specific coding rules.
#
# Run via: composer coding-rules
#         (or directly: bash bin/coding-rules-check.sh)
#
# Each rule has its own check function. On violation the script appends a
# line to $VIOLATIONS_FILE and exits 1 at the end. Exit 0 = all rules pass.
#
# Generated by wp-plugin-onboard skill. Customize each check for your
# plugin's specific rules — the two below are the most-common patterns:
#   1. Native current_user_can() with a custom-ability slug (broken when
#      abilities have default_roles=[] — common in custom-RBAC plugins)
#   2. REST __return_true outside an explicit allowlist (security gate
#      against silently-public endpoints)

set -uo pipefail

SCRIPT_DIR="$(cd "$(dirname "${BASH_SOURCE[0]}")" && pwd)"
PLUGIN_DIR="$(cd "$SCRIPT_DIR/.." && pwd)"

VIOLATIONS_FILE="$(mktemp)"
trap 'rm -f "$VIOLATIONS_FILE"' EXIT

violation() {
    echo "✗ $*"
    echo "v" >> "$VIOLATIONS_FILE"
}
ok() { echo "✓ $*"; }
violations_count() { wc -l < "$VIOLATIONS_FILE" | tr -d ' '; }

# ------------------------------------------------------------------------------

# Rule 1: never use current_user_can() with a custom-ability slug.
# Architecture: if your plugin registers abilities with empty default_roles
# (common in custom RBAC), current_user_can('plugin/foo') returns false
# for everyone. The plugin's own Permission_Engine (or equivalent) is the
# only correct gate.
#
# Customize: replace wb-gamification with your plugin's ability namespace.
check_no_native_cap_check_for_plugin_abilities() {
    # WB Gamification uses src/ (PSR-4) instead of includes/.
    # Abilities namespace is wb-gamification/* — those slugs are for the
    # WP Abilities API discovery surface, not for current_user_can() gates.
    local hits
    hits=$(grep -rEn "current_user_can\(\s*['\"]wb-gamification/" "$PLUGIN_DIR/src/" 2>/dev/null \
            | grep -vE "AbilitiesRegistration\.php|/tests/" \
            || true)
    if [ -n "$hits" ]; then
        violation "Rule 1 — current_user_can('wb-gamification/...') outside AbilitiesRegistration:"
        echo "$hits" | sed 's/^/    /'
        echo "    Fix: ability slugs (wb-gamification/foo) are not WP capabilities."
        echo "         Use a real cap (e.g. 'manage_options' or wb_gam_*) for permission gates."
    else
        ok "Rule 1 — no native cap checks for wb-gamification/* abilities"
    fi
}

# Rule 2: REST permission_callback must not use the bare '__return_true'
# string outside the allowlist of intentionally-public controllers (auth,
# catalog, certificate verification, third-party webhooks).
#
# Customize: list every controller file that legitimately ships
# __return_true. Document the reason in audit/FEATURE_AUDIT.md §3.
check_unauthenticated_rest_allowlist() {
    # Documented public endpoints — see audit/ROLE_MATRIX.md "REST API
    # permission map" for the rationale on each. New __return_true outside
    # this allowlist signals an unintended public route.
    local allowed_files=(
        'AbilitiesRegistration.php'   # /abilities — WP Abilities API discovery
        'ActionsController.php'       # /actions, /actions/{id} — public action catalog
        'BadgesController.php'        # /badges, /badges/{id} READ — public badge defs
        'BadgeShareController.php'    # /badges/{id}/share/{user_id} — OG share endpoint
        'CapabilitiesController.php'  # /capabilities — discovery for mobile/remote
        'ChallengesController.php'    # /challenges, /challenges/{id} READ — public catalog
        'CredentialController.php'    # /badges/{id}/credential/{user_id} — verifiable credential
        'KudosController.php'         # /kudos READ — public feed
        'LeaderboardController.php'   # /leaderboard, /leaderboard/group/{id} — public ranks
        'LevelsController.php'        # /levels — public level defs
        'OpenApiController.php'       # /openapi.json — public spec
        'PointTypesController.php'    # /point-types READ — public catalogue (consumers need it to scope queries)
        'PointTypeConversionsController.php' # /point-type-conversions READ — public list of active conversion rules
        'RedemptionController.php'    # /redemptions/items READ — public catalog
    )

    local exclude_pattern
    exclude_pattern=$( IFS='|' ; echo "${allowed_files[*]}" )

    local hits
    hits=$(grep -rEn "['\"]__return_true['\"]" "$PLUGIN_DIR/src/API/" 2>/dev/null \
            | grep -vE "$exclude_pattern" \
            || true)

    if [ -n "$hits" ]; then
        violation "Rule 2 — __return_true on a non-allowlisted REST controller:"
        echo "$hits" | sed 's/^/    /'
        echo "    Fix: replace with a named permission method that returns true|WP_Error,"
        echo "         OR add the controller to allowed_files[] in this script + document in"
        echo "         audit/ROLE_MATRIX.md if the route is intentionally public."
    else
        ok "Rule 2 — REST __return_true usage is on the allowlist only"
    fi
}

# Rule 2b: a PUBLIC route that reads a CALLER-SUPPLIED user_id must consult Privacy.
#
# Rule 2 above allowlists whole FILES, and that granularity is exactly how we shipped an
# unauthenticated IDOR: ChallengesController was allowlisted as "public catalog", which is true --
# the catalogue IS public. But the same routes also accept `?user_id=`, and that parameter enriched
# the response with that member's challenge progress. So the file-level reason was correct and the
# route was still leaking: an anonymous caller with no cookie walked ?user_id=1,2,3... and harvested
# progress for members who had opted OUT of a public profile. Rule 2 was green throughout.
#
# A reason that is true about a file can be false about a parameter. This rule closes that gap: if a
# controller ships __return_true AND reads user_id from the request, it must either consult Privacy,
# or carry an explicit annotation saying why that member data is public to strangers.
#
# The annotation is deliberately awkward to write. It is a place to state a decision, not a snooze
# button -- an allowlist you can join without saying anything is how the last one lied to us.
check_public_routes_gate_user_data() {
    local offenders=()

    for file in "$PLUGIN_DIR"/src/API/*.php; do
        [ -f "$file" ] || continue

        grep -q "__return_true" "$file" || continue

        # Caller-supplied only: $request['user_id'] / get_param('user_id'). A 'user_id' key in a
        # RESPONSE schema is not an input and must not trip this rule (Leaderboard, Kudos,
        # Redemption and Capabilities all publish that field while reading get_current_user_id()).
        grep -qE "\\\$request\[ *'user_id' *\]|get_param\( *'user_id' *\)" "$file" || continue

        grep -q "Privacy::" "$file" && continue
        grep -q "@public-member-data" "$file" && continue

        offenders+=( "$(basename "$file")" )
    done

    if [ ${#offenders[@]} -gt 0 ]; then
        violation "Rule 2b — public route reads a caller-supplied user_id without a Privacy check:"
        printf '    %s\n' "${offenders[@]}"
        echo "    Any stranger can iterate user_id and harvest that member's data."
        echo "    Fix: gate on \\WBGam\\Engine\\Privacy::can_view_public_profile( \$user_id ) and"
        echo "         degrade to a non-personal read when it fails (see ChallengesController"
        echo "         ::resolve_user_id or BadgesController::get_items),"
        echo "         OR annotate the file with '@public-member-data <why this is public>' if the"
        echo "         exposure is deliberate (a verifiable credential, a share card the member"
        echo "         published themselves)."
    else
        ok "Rule 2b — every public route that takes a user_id gates it or documents why not"
    fi
}

# Rule 3: no inline `style="..."` attributes in admin PHP.
# Per plan/ARCHITECTURE.md "no inline JS or CSS" — admin pages must use the
# wbgam-* utility classes in assets/css/admin.css, never inline styles.
# Exception: dynamic CSS-variable pass-throughs (style="--var:value")
# and dynamic-width markers (style="width:N%") that serve as data conduits.
check_no_inline_styles_in_admin_php() {
    local hits
    hits=$(grep -rEn 'style="[^"]+"' "$PLUGIN_DIR/src/Admin/" 2>/dev/null \
            | grep -vE 'style="--[a-zA-Z][a-zA-Z0-9_-]*:' \
            | grep -vE 'style="width:<\?php' \
            || true)
    if [ -n "$hits" ]; then
        violation "Rule 3 — inline style=\"...\" in admin PHP (use wbgam-* utility classes):"
        echo "$hits" | sed 's/^/    /'
        echo "    Fix: extract to a utility class in assets/css/admin.css and reference via class=\"...\"."
    else
        ok "Rule 3 — no inline style= attributes in src/Admin/"
    fi
}

# Rule 4: no inline <script> blocks in PHP. Move to assets/js/ + wp_enqueue_script.
# Scans only *.php under src/ (skips JS / CSS / comments / vendor / tests).
# Allowlist: ProfilePage.php — JSON-LD MUST emit an inline
# <script type="application/ld+json"> per W3C spec for Schema.org. The JSON
# payload is per-request and can't be moved to a static asset file.
check_no_inline_scripts_in_php() {
    local hits
    hits=$(grep -rEn --include='*.php' '<script(\s|>)' "$PLUGIN_DIR/src/" 2>/dev/null \
            | grep -vE '/(tests|vendor)/' \
            | grep -vE '^\s*[*]' \
            | grep -vE '^[^:]*:[0-9]+:\s*\*' \
            | grep -vE '^[^:]*:[0-9]+:\s*//' \
            | grep -vE 'src/Engine/ProfilePage\.php.*ld\+json' \
            || true)
    if [ -n "$hits" ]; then
        violation "Rule 4 — inline <script> blocks in PHP (move to assets/js/ + wp_enqueue_script):"
        echo "$hits" | sed 's/^/    /'
        echo "    Fix: create assets/js/<file>.js, register via wp_enqueue_script() in enqueue_assets()."
    else
        ok "Rule 4 — no inline <script> blocks in PHP"
    fi
}

# Rule 5: no inline <style> blocks in PHP either.
# Allowlist: src/Blocks/CSS.php — the documented unique-ID-scoped block CSS
# emitter that has to ship as a single inline <style> per Phase G architecture.
check_no_inline_style_blocks_in_php() {
    local hits
    hits=$(grep -rEn --include='*.php' '<style(\s|>)' "$PLUGIN_DIR/src/" 2>/dev/null \
            | grep -vE '/(tests|vendor)/' \
            | grep -vE 'src/Blocks/CSS\.php' \
            | grep -vE '^\s*[*]' \
            | grep -vE '^[^:]*:[0-9]+:\s*\*' \
            | grep -vE '^[^:]*:[0-9]+:\s*//' \
            || true)
    if [ -n "$hits" ]; then
        violation "Rule 5 — inline <style> blocks in PHP (move to assets/css/ + wp_enqueue_style):"
        echo "$hits" | sed 's/^/    /'
        echo "    Fix: extract to assets/css/<file>.css, register via wp_enqueue_style()."
    else
        ok "Rule 5 — no inline <style> blocks in PHP"
    fi
}

# ------------------------------------------------------------------------------

echo "=== WB Gamification coding-rules check ==="
echo "Plugin: $PLUGIN_DIR"
echo ""

# Rule 11: every user-scoped surface must be covered by BOTH the export and the erase.
#
# THIS RULE WAS GREEN WHILE THE ERASER LEAKED, and the reason is worth keeping.
#
# It used to check that a table name appeared ANYWHERE in Privacy.php. But that file holds two
# separate functions, and a table listed in the EXPORT satisfied the grep while the ERASE never
# deleted it. wb_gam_cohort_members, notifications_queue, user_intelligence, redemptions,
# community_challenge_contributions and api_keys were all "referenced in Privacy.php" and all
# survived a GDPR erasure request. The export was missing a different seven, including the member's
# kudos. Mere textual presence is not coverage.
#
# Both paths are now derived from the SCHEMA (MemberData::member_tables()), so a table cannot be
# forgotten — it is covered on the day it is created. This rule now verifies that the derivation is
# still in place, rather than trying to re-derive it here and drift in its own way.
#
# See plan/PRIVACY-MODEL.md § Cross-cutting principles #6.
check_privacy_coverage_for_user_scoped_surfaces() {
    local privacy_file="$PLUGIN_DIR/src/Engine/Privacy.php"
    if [ ! -f "$privacy_file" ]; then
        violation "Rule 11 — src/Engine/Privacy.php missing entirely"
        return
    fi

    local missing=""

    # User-scoped wb_gam_* tables — extracted from Installer.php CREATE TABLE
    # statements that include a `user_id` column. Each table must appear in
    # Privacy.php (as `wb_gam_<name>` literal) for both export and erase.
    local table_names
    table_names=$(awk '
        /CREATE TABLE/ { in_create = 1; tname = ""; has_uid = 0; next }
        in_create && match($0, /\{\$wpdb->prefix\}wb_gam_[a-z_]+/) {
            tname = substr($0, RSTART, RLENGTH);
            sub(/^\{\$wpdb->prefix\}/, "", tname);
        }
        in_create && /\<user_id\>/ { has_uid = 1 }
        in_create && /\)\s*\$charset_collate\s*;/ {
            if ( has_uid && tname != "" ) print tname;
            in_create = 0;
        }
    ' "$PLUGIN_DIR/src/Engine/Installer.php" 2>/dev/null | sort -u)

    local member_data="$PLUGIN_DIR/src/Engine/MemberData.php"

    if [ ! -f "$member_data" ]; then
        violation "Rule 11 — src/Engine/MemberData.php missing: nothing derives the privacy surface from the schema"
        return
    fi

    # The erase path must go through the schema-driven purge, not a hand-list.
    if ! grep -q 'MemberData::purge( $user_id )' "$privacy_file"; then
        missing="${missing}    erase_user_data() must call MemberData::purge() — a hand-listed set of tables is what leaked.\n"
    fi

    # The export must have the schema-driven catch-all, so it cannot omit a table either.
    if ! grep -q 'MemberData::export_rows( $user_id )' "$privacy_file"; then
        missing="${missing}    export_user_data() must append MemberData::export_rows() — the curated groups omitted 7 tables.\n"
    fi

    # And the derivation itself must still read the schema.
    if ! grep -q 'SHOW COLUMNS FROM' "$member_data"; then
        missing="${missing}    MemberData must derive its tables from the SCHEMA (SHOW COLUMNS). A hardcoded list drifts.\n"
    fi

    # Tables are schema-derived, so they cannot be missed — but the count is worth reporting.
    for tbl in $table_names; do
        : # covered by MemberData::member_tables(); nothing to hand-check.
    done

    # User-meta keys — every literal 'wb_gam_*' meta_key passed to
    # update_user_meta() / get_user_meta() / delete_user_meta() in src/
    # (excluding Privacy.php itself, which is the consumer side).
    local meta_keys
    meta_keys=$(grep -rEho "(update|get|add|delete)_user_meta\(\s*[^,]+,\s*['\"]wb_gam_[a-z_]+['\"]" \
                    "$PLUGIN_DIR/src/" --include="*.php" 2>/dev/null \
                | grep -vE "Privacy\.php" \
                | sed -E "s/.*['\"]( *wb_gam_[a-z_]+ *)['\"].*/\1/" \
                | tr -d ' ' \
                | sort -u)

    # User meta is NOT schema-discoverable (WordPress owns that table), so it is the one place a list
    # is unavoidable — which makes it the one place this rule still has to do real work. The keys live
    # in MemberData::USER_META_KEYS (erase) and must also appear in Privacy.php (export).
    for key in $meta_keys; do
        if ! grep -q "['\"]$key['\"]" "$member_data"; then
            missing="${missing}    User meta '$key' — not in MemberData::USER_META_KEYS, so a GDPR erase leaves it behind\n"
        fi
        if ! grep -q "['\"]$key['\"]" "$privacy_file"; then
            missing="${missing}    User meta '$key' — not in Privacy.php, so the data export omits it\n"
        fi
    done

    if [ -n "$missing" ]; then
        violation "Rule 11 — user-scoped surfaces missing from Privacy::export_user_data + erase_user_data:"
        printf "%b" "$missing"
        echo "    Fix: meta keys go in MemberData::USER_META_KEYS (erase) AND Privacy.php (export)."
        echo "         See plan/PRIVACY-MODEL.md § Cross-cutting principles #6."
    else
        ok "Rule 11 — export + erase are both derived from the schema; every meta key is covered"
    fi
}

# Rule 12: every as_schedule_*/as_enqueue_* call must be either preceded by an
# as_has_scheduled_action() guard in the same method OR carry an @as-fire-once
# docblock annotation. Closes the bug class that caused the LeaderboardNudge
# Action Scheduler runaway in 1.4.0 (3.5M-row queue on one production install).
#
# Implementation: bin/check-as-schedule-guard.php (PHP token-walker, mirrors
# the bin/check-boot-invariants.php + bin/check-badge-condition-contract.php
# pattern). PHPStan was the original target but the local PHPStan install
# is silently non-functional in this environment, so the token-walker is the
# robust path. Lives inside this stage 2.1 (coding-rules) rather than as a
# new stage, per the "fold into existing gate" preference.
check_as_schedule_guard() {
    local out
    out=$(php "$PLUGIN_DIR/bin/check-as-schedule-guard.php" 2>&1)
    local rc=$?
    if [ "$rc" -eq 0 ]; then
        ok "Rule 12 — every AS-schedule call is guarded or @as-fire-once annotated"
    else
        violation "Rule 12 — AS-schedule guard contract:"
        echo "$out" | sed 's/^/    /'
    fi
}

# Rule 13: the Hub's legacy --gam-accent token must bridge to the standard
# --wb-gam-color-accent token, never a hardcoded hex. hub.css forked its own
# --gam-* family; a hardcoded --gam-accent means the site owner's
# Settings > Appearance accent silently does not apply to the Hub (the
# 10060536808 bug). Every --gam-accent DEFINITION in the source stylesheet
# must reference var(--wb-gam-color-accent, ...). Only the source hub.css is
# checked; hub-rtl.css / *.min.css are generated from it. (Matches the exact
# token only — --gam-accent-light / --gam-accent-text are derived usages.)
check_hub_accent_bridged_to_standard_token() {
    local src="$PLUGIN_DIR/assets/css/hub.css"
    [ -f "$src" ] || { ok "Rule 13 — hub.css absent, skipped"; return; }
    local hits
    hits=$(grep -nE -- '--gam-accent:' "$src" 2>/dev/null \
            | grep -v 'var(--wb-gam-color-accent' \
            || true)
    if [ -n "$hits" ]; then
        violation "Rule 13 — --gam-accent defined without bridging to --wb-gam-color-accent (owner accent won't reach the Hub — see BC 10060536808):"
        echo "$hits" | sed 's/^/    /'
    else
        ok "Rule 13 — Hub --gam-accent bridges to --wb-gam-color-accent"
    fi
}

# Rule 14: never pass raw $_POST straight into update_option() in admin code.
# Admin saves must read $_POST into a sanitized variable first (the whole
# admin surface either routes through SettingsPage::handle_save — nonce + cap
# verified once, then per-section sanitize — or gates its own handler with
# check_admin_referer). A literal `update_option( 'key', $_POST[...] )` skips
# sanitization AND is the shape wppqa's "direct $_POST to update_option" flag
# looks for; banning it keeps that class of finding at zero and forces the
# established sanitize-then-save pattern.
check_no_raw_post_to_update_option() {
    # A safe line wraps $_POST in a sanitizer/guard on the same statement
    # (absint / sanitize_* / intval / (int) / (bool) / isset()-ternary). Only
    # a raw $_POST with NONE of those is a real violation.
    local hits
    hits=$(grep -rEn "update_option\([^)]*\\\$_(POST|REQUEST)" "$PLUGIN_DIR/src/" 2>/dev/null \
            | grep -v "/tests/" \
            | grep -vE "absint|sanitize_|intval|\(int\)|\(bool\)|isset\(" || true)
    if [ -n "$hits" ]; then
        violation "Rule 14 — raw \$_POST/\$_REQUEST passed into update_option() (sanitize on the same statement):"
        echo "$hits" | sed 's/^/    /'
    else
        ok "Rule 14 — no raw \$_POST piped into update_option()"
    fi
}

# Rule 15: every block render.php that loops over a collection must also
# render an empty state. The "silent empty state" bug class (wppqa) is a
# frontend list that renders nothing when the collection is empty — a blank
# block on a fresh site. Every current block guards this (empty()/count()/an
# `__empty` element); this gate keeps a NEW block from shipping a bare loop.
check_blocks_have_empty_state() {
    local missing=""
    local f base
    for f in "$PLUGIN_DIR"/src/Blocks/*/render.php; do
        [ -f "$f" ] || continue
        if grep -q "foreach" "$f" 2>/dev/null; then
            if ! grep -qE "empty\(|__empty|count\(|--empty|EmptyState" "$f" 2>/dev/null; then
                base=$(basename "$(dirname "$f")")
                missing="${missing} ${base}"
            fi
        fi
    done
    if [ -n "$missing" ]; then
        violation "Rule 15 — block(s) loop over a collection with no empty state (silent-blank on empty data):$missing"
    else
        ok "Rule 15 — every looping block renders an empty state"
    fi
}

# Rule 16: any plugin JS that calls fetch() must apply an AbortSignal timeout,
# so a slow or dead host can never freeze the UI. The two shared wrappers
# (admin-rest-utils.js apiFetch, sdk client) and every raw frontend fetch use
# AbortSignal.timeout(); this gate keeps a NEW fetch from shipping without one.
# Scans plugin-authored JS only (skips minified + the bundled wbcom-family lib).
check_fetch_has_timeout() {
    local missing="" f
    while IFS= read -r f; do
        [ -f "$f" ] || continue
        if grep -q "fetch(" "$f" 2>/dev/null && ! grep -q "AbortSignal" "$f" 2>/dev/null; then
            missing="${missing} ${f#"$PLUGIN_DIR"/}"
        fi
    done < <(find "$PLUGIN_DIR/assets/js" "$PLUGIN_DIR/src/Blocks" -name '*.js' ! -name '*.min.js' 2>/dev/null)
    if [ -n "$missing" ]; then
        violation "Rule 16 — fetch() without an AbortSignal timeout (a hung host freezes the UI):$missing"
    else
        ok "Rule 16 — every fetch() applies an AbortSignal timeout"
    fi
}

# Rule 17: any authored CSS that defines a keyframe animation must also carry
# a prefers-reduced-motion guard (WCAG 2.3.3 — vestibular safety). Applies to
# source CSS only (skips generated -rtl / .min variants, which inherit it).
check_animations_respect_reduced_motion() {
    local missing="" f
    while IFS= read -r f; do
        [ -f "$f" ] || continue
        case "$f" in
            *.min.css|*-rtl.css|*-rtl.min.css ) continue ;;
        esac
        if grep -qE "@keyframes|animation:" "$f" 2>/dev/null && ! grep -q "prefers-reduced-motion" "$f" 2>/dev/null; then
            missing="${missing} ${f#"$PLUGIN_DIR"/}"
        fi
    done < <(find "$PLUGIN_DIR/assets/css" "$PLUGIN_DIR/src" -name '*.css' 2>/dev/null)
    if [ -n "$missing" ]; then
        violation "Rule 17 — CSS defines animation without a prefers-reduced-motion guard (WCAG 2.3.3):$missing"
    else
        ok "Rule 17 — every animated CSS file guards prefers-reduced-motion"
    fi
}

check_no_native_cap_check_for_plugin_abilities
check_unauthenticated_rest_allowlist
check_public_routes_gate_user_data
check_no_inline_styles_in_admin_php
check_no_inline_scripts_in_php
check_no_inline_style_blocks_in_php
check_privacy_coverage_for_user_scoped_surfaces
check_as_schedule_guard
check_hub_accent_bridged_to_standard_token
check_no_raw_post_to_update_option
check_blocks_have_empty_state
check_fetch_has_timeout
check_animations_respect_reduced_motion

echo ""
COUNT=$(violations_count)
if [ "$COUNT" -eq 0 ]; then
    echo "All coding rules pass."
    exit 0
else
    echo "$COUNT violation(s) found. See CLAUDE.md \"Important patterns\"."
    exit 1
fi
